mapper.insert:
INSERT INTO attendance_patch_apply (
    user_id, unit_id, attendance_date, patch_type, patch_time, reason, status,
    approve_user_id, approve_time, approve_comment, create_time, update_time, valid_flag
)
VALUES (
    #{userId}, #{unitId}, #{attendanceDate}, #{patchType}, #{patchTime}, #{reason}, #{status},
    #{approveUserId}, #{approveTime}, #{approveComment}, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, #{validFlag}
)

mapper.select:
SELECT id, user_id, unit_id, attendance_date, patch_type, patch_time, reason, status,
       approve_user_id, approve_time, approve_comment, create_time, update_time, valid_flag
FROM attendance_patch_apply
WHERE user_id = #{userId}
  AND attendance_date = #{attendanceDate}
  AND patch_type = #{patchType}
  AND status = 'PENDING'
  AND valid_flag = 1
ORDER BY id DESC
LIMIT 1

SELECT COUNT(1)
FROM attendance_patch_apply a
WHERE a.user_id = #{userId}
  AND a.valid_flag = 1

    AND a.patch_type = #{request.patchType}


    AND a.status = #{request.status}


    AND a.attendance_date >= CAST(#{request.dateFrom} AS date)


    AND a.attendance_date <= CAST(#{request.dateTo} AS date)

SELECT a.id, a.user_id, a.unit_id, a.attendance_date, a.patch_type, a.patch_time, a.reason, a.status, a.approve_user_id, a.approve_time, a.approve_comment, a.create_time, a.update_time, a.valid_flag, u.username, u.real_name, su.unit_name, au.username AS approve_username, au.real_name AS approve_real_name FROM attendance_patch_apply a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id LEFT JOIN sys_user au ON au.id = a.approve_user_id WHERE a.user_id = #{userId} AND a.valid_flag = 1
AND a.patch_type = #{request.patchType}
AND a.status = #{request.status}
AND a.attendance_date >= CAST(#{request.dateFrom} AS date)
AND a.attendance_date <= CAST(#{request.dateTo} AS date)
ORDER BY a.create_time DESC, a.id DESC LIMIT #{request.pageSize} OFFSET #{request.offset}

SELECT COUNT(1) FROM attendance_patch_apply a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE a.valid_flag = 1 AND u.is_deleted = FALSE AND a.user_id != #{currentUserId}
AND u.tree_path LIKE CONCAT(#{treePathPrefix}, '%')
AND ( u.username LIKE CONCAT('%', #{request.keywords}, '%') OR u.real_name LIKE CONCAT('%', #{request.keywords}, '%') )
AND a.patch_type = #{request.patchType}
AND a.status = #{request.status}
AND a.attendance_date >= CAST(#{request.dateFrom} AS date)
AND a.attendance_date <= CAST(#{request.dateTo} AS date)

SELECT a.id, a.user_id, a.unit_id, a.attendance_date, a.patch_type, a.patch_time, a.reason, a.status, a.approve_user_id, a.approve_time, a.approve_comment, a.create_time, a.update_time, a.valid_flag, u.username, u.real_name, su.unit_name, au.username AS approve_username, au.real_name AS approve_real_name FROM attendance_patch_apply a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id LEFT JOIN sys_user au ON au.id = a.approve_user_id WHERE a.valid_flag = 1 AND u.is_deleted = FALSE AND a.user_id != #{currentUserId}
AND u.tree_path LIKE CONCAT(#{treePathPrefix}, '%')
AND ( u.username LIKE CONCAT('%', #{request.keywords}, '%') OR u.real_name LIKE CONCAT('%', #{request.keywords}, '%') )
AND a.patch_type = #{request.patchType}
AND a.status = #{request.status}
AND a.attendance_date >= CAST(#{request.dateFrom} AS date)
AND a.attendance_date <= CAST(#{request.dateTo} AS date)
ORDER BY CASE WHEN a.status = 'PENDING' THEN 0 ELSE 1 END, a.create_time DESC, a.id DESC LIMIT #{request.pageSize} OFFSET #{request.offset}
